   182|export function mergeMemberRegistryRecords(
   183|  existing: MemberRegistryRecord[],
   184|  incoming: MemberRegistryRecord[]
   185|): MemberRegistryRecord[] {
   186|  const registry = new Map<string, MemberRegistryRecord>();
   187|  const aliasToPrimary = new Map<string, string>();
   188|
   189|  const upsertRecord = (record: MemberRegistryRecord) => {
   190|    const aliases = getRecordAliases(record);
   191|    const matchedPrimaryKeys = Array.from(
   192|      new Set(
   193|        aliases
   194|          .map((alias) => aliasToPrimary.get(alias))
   195|          .filter((value): value is string => typeof value === 'string' && value.length > 0)
   196|      )
   197|    );
   198|
   199|    const primaryKey = matchedPrimaryKeys[0] ?? getRecordKey(record);
   200|    let mergedRecord: MemberRegistryRecord | null = registry.get(primaryKey) ?? null;
   201|
   202|    for (const duplicatePrimaryKey of matchedPrimaryKeys.slice(1)) {
   203|      const duplicateRecord = registry.get(duplicatePrimaryKey);
   204|      if (!duplicateRecord) continue;
   205|
   206|      mergedRecord = mergedRecord
   207|        ? mergeTwoMemberRegistryRecords(mergedRecord, duplicateRecord)
   208|        : duplicateRecord;
   209|
   210|      registry.delete(duplicatePrimaryKey);
   211|      for (const duplicateAlias of getRecordAliases(duplicateRecord)) {
   212|        aliasToPrimary.set(duplicateAlias, primaryKey);
   213|      }
   214|    }
   215|
   216|    mergedRecord = mergedRecord
   217|      ? mergeTwoMemberRegistryRecords(mergedRecord, record)
   218|      : record;
   219|
   220|    registry.set(primaryKey, mergedRecord);
   221|    for (const alias of getRecordAliases(mergedRecord)) {
   222|      aliasToPrimary.set(alias, primaryKey);
   223|    }
   224|  };
   225|
   226|  for (const record of sortMemberRegistryRecords(existing)) {
   227|    upsertRecord(record);
   228|  }
   229|
   230|  for (const record of incoming) {
   231|    upsertRecord(record);
   232|  }
   233|
   234|  return sortMemberRegistryRecords(Array.from(registry.values())).slice(0, MEMBER_REGISTRY_MAX_ITEMS);
