     1|/**
     2| * useReelPlayback — manages the active reel index, screen focus, and
     3| * the playback condition for the Instagram-style player lifecycle.
     4| *
     5| * Playback condition:
     6| *   shouldPlay = isScreenFocused && isAppForeground && isItemActive
     7| *
     8| * Only ONE reel may play at a time. The previous and next reels are
     9| * mounted (poster-only) but never play. All others are unmounted.
    10| */
    11|import { useCallback, useRef } from 'react';
    12|import { useState } from 'react';
    13|import type { ViewToken } from 'react-native';
    14|import { useFocusEffect } from 'expo-router';
    15|import { useAppForeground } from './useAppForeground';
    16|
    17|export interface ReelPlaybackState {
    18|  activeIndex: number;
    19|  isScreenFocused: boolean;
    20|  isAppForeground: boolean;
    21|  setActiveIndex: (index: number) => void;
    22|  handleViewableItemsChanged: (info: { viewableItems: ViewToken[] }) => void;
    23|  viewabilityConfig: { itemVisiblePercentThreshold: number };
    24|  shouldPlay: (index: number) => boolean;
    25|  shouldMount: (index: number, totalItems: number) => boolean;
    26|}
    27|
    28|export function useReelPlayback(): ReelPlaybackState {
    29|  const isAppForeground = useAppForeground();
    30|  const [isScreenFocused, setIsScreenFocused] = useState<boolean>(true);
    31|  const [activeIndex, setActiveIndexState] = useState<number>(0);
    32|  const activeIndexRef = useRef<number>(0);
    33|
    34|  // Track screen focus via useFocusEffect — true when this screen is
    35|  // the active route, false when the user navigates away.
    36|  useFocusEffect(
    37|    useCallback(() => {
    38|      setIsScreenFocused(true);
    39|      return () => {
    40|        setIsScreenFocused(false);
    41|      };
    42|    }, []),
    43|  );
    44|
    45|  const updateActiveIndex = useCallback((index: number) => {
    46|    activeIndexRef.current = index;
    47|    setActiveIndexState(index);
    48|  }, []);
    49|
    50|  const handleViewableItemsChanged = useCallback(
    51|    (info: { viewableItems: ViewToken[] }) => {
    52|      const first = info.viewableItems.find((v) => v.isViewable);
    53|      if (first && typeof first.index === 'number') {
    54|        updateActiveIndex(first.index);
    55|      }
    56|    },
    57|    [updateActiveIndex],
    58|  );
    59|
    60|  // 80% visibility threshold — stricter than the old 60% to prevent
    61|  // overlap during fast scroll where two players briefly play at once.
    62|  const viewabilityConfig = useRef({ itemVisiblePercentThreshold: 80 }).current;
    63|
    64|  const shouldPlay = useCallback(
    65|    (index: number): boolean => {
    66|      if (!isScreenFocused) return false;
    67|      if (!isAppForeground) return false;
    68|      return index === activeIndexRef.current;
    69|    },
    70|    [isScreenFocused, isAppForeground],
    71|  );
    72|
    73|  /**
    74|   * Only mount the previous, active, and next items (max 3).
    75|   * All other items display poster/thumbnail only and their
    76|   * video players are unmounted to free native resources.
    77|   */
    78|  const shouldMount = useCallback(
    79|    (index: number, totalItems: number): boolean => {
    80|      if (totalItems <= 3) return true;
    81|      const current = activeIndexRef.current;
    82|      return Math.abs(index - current) <= 1;
    83|    },
    84|    [],
    85|  );
    86|
    87|  return {
    88|    activeIndex,
    89|    isScreenFocused,
    90|    isAppForeground,
    91|    setActiveIndex: updateActiveIndex,
    92|    handleViewableItemsChanged,
    93|    viewabilityConfig,
    94|    shouldPlay,
    95|    shouldMount,
